def maximum_sum_after_removal(nums):
    count = {}
    for num in nums:
        if num in count:
            count[num] += 1
        else:
            count[num] = 1
    result = []
    for key in count:
        if count[key] > 1:
            result.append(key)
    if not result:
        return sum(nums)
    max_sum = float('-inf')
    for i in range(1 << len(result)):
        temp = nums[:]
        for j in range(len(result)):
            if (i & (1 << j)):
                temp = [num for num in temp if num != result[j]]
        max_sum = max(max_sum, sum(temp))
    return max_sum

