def equalize_array(nums, target_sum):
    count_dict = {}
    for num in nums:
        if num in count_dict:
            count_dict[num] += 1
        else:
            count_dict[num] = 1

    result = []
    for key in sorted(count_dict.keys()):
        result.extend([key] * count_dict[key])

    total_sum = sum(result)
    if total_sum == target_sum:
        return result

    for i in range(len(result)):
        for j in range(i + 1, len(result)):
            if result[i] == result[j]:
                del result[j]
                break

    return result


