def find_unique_elements(nums, target_sum):
    def backtrack(start, path, target):
        if target < 0:
            return
        if target == 0:
            result.append(path)
            return
        for i in range(start, len(nums)):
            if i > start and nums[i] == nums[i - 1]:
                continue
            backtrack(i + 1, path + [nums[i]], target - nums[i])

    nums.sort()
    result = []
    backtrack(0, [], target_sum)
    return result

